from flask import Flask, request, jsonify
import numpy as np
import face_recognition
import os
import joblib
from sklearn.preprocessing import LabelEncoder
from sklearn.svm import SVC

app = Flask(__name__)

# Load employee images and encode faces
def load_employee_data(employee_images_path):
    known_face_encodings = []
    known_face_labels = []
    
    for filename in os.listdir(employee_images_path):
        if filename.endswith(".jpg") or filename.endswith(".png"):
            image = face_recognition.load_image_file(os.path.join(employee_images_path, filename))
            encoding = face_recognition.face_encodings(image)
            if encoding:
                known_face_encodings.append(encoding[0])
                known_face_labels.append(filename.split('.')[0])  # Use filename as label

    return np.array(known_face_encodings), known_face_labels

# Train the model
def train_model(encodings, labels):
    le = LabelEncoder()
    labels_encoded = le.fit_transform(labels)
    clf = SVC(probability=True)
    clf.fit(encodings, labels_encoded)
    joblib.dump(clf, 'model.pkl')
    joblib.dump(le, 'label_encoder.pkl')

# Load data and train model
employee_images_path = 'employee_photos'
encodings, labels = load_employee_data(employee_images_path)
train_model(encodings, labels)

# Load model and label encoder
model = joblib.load('model.pkl')
label_encoder = joblib.load('label_encoder.pkl')

@app.route('/recognize', methods=['POST'])
def recognize():
    file = request.files['image']
    image = face_recognition.load_image_file(file)
    encoding = face_recognition.face_encodings(image)

    if not encoding:
        return jsonify({"error": "No face found in the image."}), 400

    encoding = encoding[0].reshape(1, -1)
    probabilities = model.predict_proba(encoding)
    confidence_scores = {label: prob for label, prob in zip(label_encoder.classes_, probabilities[0])}

    return jsonify(confidence_scores)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)